import logo from "./logo.svg";
import "./App.css";
import { useState } from "react";

const App = function () {
    return (
        <>
            <Header />
            <Modal />
            <AlertModal />
            <TodoBox />
        </>
    );
};

const Header = function () {
    return (
        <>
            <header className="header">
                <h1 className="header-app-name">Todoアプリ</h1>
                <select className="filter">
                    <option value="all" selected>
                        全て
                    </option>
                    <option value="yet">未着手</option>
                    <option value="in-progress">進行中</option>
                    <option value="done">完了</option>
                </select>
            </header>
        </>
    );
};
const Modal = function () {
    return (
        <div className="todo-modal hidden">
            <button type="button" className="todo-modal--close">
                &times;
            </button>
            <div className="input">
                <input type="text" className="input--main" placeholder="main" />
                <input type="text" className="input--sub" placeholder="sub" />
                <input type="date" className="input--start" placeholder="start" />
                <input type="date" className="input--deadline" placeholder="deadline" />
            </div>
            <button type="button" className="add-new-todo-btn">
                追加
            </button>
        </div>
    );
};
const AlertModal = function () {
    return (
        <div className="alert-modal hidden">
            <button type="button" className="alert-modal--close">
                &times;
            </button>
        </div>
    );
};
const TodoBox = function () {
    return (
        <>
            <AddCard />
        </>
    );
};
const AddCard = function () {
    return (
        <div className="add-card card--layout">
            <div className="add-card__box">
                <p className="add-card--text">追加</p>
                <button type="button" className="add-card__btn">
                    <svg
                        xmlns="http://www.w3.org/2000/svg"
                        viewBox="0 0 24 24"
                        fill="currentColor"
                        className="add-card__icon"
                    >
                        <path
                            fill-rule="evenodd"
                            d="M12 3.75a.75.75 0 0 1 .75.75v6.75h6.75a.75.75 0 0 1 0 1.5h-6.75v6.75a.75.75 0 0 1-1.5 0v-6.75H4.5a.75.75 0 0 1 0-1.5h6.75V4.5a.75.75 0 0 1 .75-.75Z"
                            clip-rule="evenodd"
                        />
                    </svg>
                </button>
            </div>
        </div>
    );
};
export default App;
